CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE TABLE IF NOT EXISTS merchants(id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),name TEXT NOT NULL,email TEXT UNIQUE NOT NULL,password_hash TEXT NOT NULL,phone TEXT NOT NULL,address TEXT,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS drivers(id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),name TEXT NOT NULL,email TEXT UNIQUE NOT NULL,password_hash TEXT NOT NULL,phone TEXT NOT NULL,is_active BOOLEAN DEFAULT true,last_lat DECIMAL(9,6),last_lng DECIMAL(9,6),created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS admins(id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),name TEXT NOT NULL,email TEXT UNIQUE NOT NULL,password_hash TEXT NOT NULL,created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS deliveries(id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),merchant_id UUID REFERENCES merchants(id),driver_id UUID REFERENCES drivers(id),pickup_address TEXT NOT NULL,pickup_barcode TEXT UNIQUE NOT NULL,total_stops INT NOT NULL DEFAULT 1,price DECIMAL(8,2) NOT NULL,status TEXT NOT NULL DEFAULT 'pending',notes TEXT,total_miles DECIMAL(8,2) DEFAULT 0,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS delivery_stops(id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),delivery_id UUID REFERENCES deliveries(id),stop_order INT NOT NULL,customer_name TEXT NOT NULL,customer_phone TEXT NOT NULL,address TEXT NOT NULL,tracking_id TEXT UNIQUE NOT NULL,otp TEXT NOT NULL,status TEXT NOT NULL DEFAULT 'pending',delivered_at TIMESTAMPTZ,created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS invoices(id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),merchant_id UUID REFERENCES merchants(id),period_start DATE NOT NULL,period_end DATE NOT NULL,total_routes INT DEFAULT 0,total_stops INT DEFAULT 0,subtotal DECIMAL(10,2) DEFAULT 0,tax DECIMAL(10,2) DEFAULT 0,total DECIMAL(10,2) DEFAULT 0,created_at TIMESTAMPTZ DEFAULT NOW());
CREATE INDEX IF NOT EXISTS idx_deliveries_merchant ON deliveries(merchant_id);
CREATE INDEX IF NOT EXISTS idx_deliveries_driver ON deliveries(driver_id);
CREATE INDEX IF NOT EXISTS idx_stops_delivery ON delivery_stops(delivery_id);
CREATE INDEX IF NOT EXISTS idx_stops_tracking ON delivery_stops(tracking_id);
